SELECT event_name, event_date, spectator_count
FROM racing_events
ORDER BY spectator_count DESC;

SELECT tot_pts
FROM team_seasons
WHERE team_id = 0 AND season_id = 0;

SELECT SUM(tot_pts) AS total_points
FROM team_performance
WHERE team_id = 0;

SELECT SUM(tot_pts) AS total_points
FROM team_seasons
WHERE team_id = 1;

SELECT event_name 
FROM racing_events
WHERE event_id = 0;

SELECT tot_pts, race_pts, bns_pts, pen_pts
FROM team_performance
WHERE team_id = 0 AND event_id = 0;
